def check_rate_limit(user_id):
    """检查用户是否在 10 秒内已下过单。返回 True 表示被限流。"""
    now = time.time()
    last_time = _rate_limit_store.get(user_id)
    if last_time and (now - last_time) < 10:
        return True  # 被限流
    return False  # 未被限流


